    document.querySelectorAll('.follow-btn-sm').forEach(btn => btn.onclick = (e) => { e.stopPropagation(); btn.innerText = btn.innerText === 'Follow' ? 'Following' : 'Follow'; btn.style.background = btn.innerText === 'Following' ? '#8b5cf6' : 'transparent'; showToast(btn.innerText === 'Following' ? 'Followed!' : 'Unfollowed'); });
