                                    <div style="width: 2.5rem; height: 2.5rem; background: linear-gradient(135deg, #8b5cf6, #ec4899); border-radius: 0.5rem; display: flex; align-items: center; justify-content: center;"><i class="fas fa-play" style="font-size: 0.8rem;"></i></div>
